function getComponentName(fiber) {
    if (!fiber) return 'Not found';
    while(fiber){
        let name = '';
        if (fiber.type && 'function' == typeof fiber.type) {
            if (fiber.type.name) name = fiber.type.name;
            if (fiber.type.displayName) name = fiber.type.displayName;
        } else if (fiber.type && 'string' == typeof fiber.type) {
            fiber = fiber.return;
            continue;
        } else if (fiber.elementType && 'function' == typeof fiber.elementType) {
            if (fiber.elementType.name) name = fiber.elementType.name;
            if (fiber.elementType.displayName) name = fiber.elementType.displayName;
        }
        if (name && fiber._debugSource) return name;
        fiber = fiber.return;
    }
    return 'Anonymous';
}
export { getComponentName };
